1	import { useEffect, useRef, useCallback, useState } from "react";
2	import type {
3	  Shape,
4	  ShapeType,
5	  ShapePatch,
6	  Operation,
7	  UndoEntry,
8	  PresenceUser,
9	  ServerMessage,
10	  ClientMessage,
11	} from "../types.ts";
12	import { getStoredToken } from "../authStore.ts";
13	import { getCanvasDetail, ApiError } from "../api.ts";
14	import { renderScene, hitTest, hitTestHandle } from "../canvasRenderer.ts";
15	import type { CursorInfo } from "../canvasRenderer.ts";
16	import { applyOp } from "../operations.ts";
17	import Toolbar from "./Toolbar.tsx";
18	import type { Tool } from "./Toolbar.tsx";
19	import InvitePanel from "./InvitePanel.tsx";
20	
21	interface CanvasPageProps {
22	  canvasId: string;
23	  onBack: () => void;
24	  onLogout: () => void;
25	}
26	
27	// Interaction mode during mouse drag
28	type DragMode =
29	  | { kind: "none" }
30	  | { kind: "draw"; startX: number; startY: number; previewShape: Shape }
31	  | {
32	      kind: "move";
33	      shapeId: string;
34	      startX: number;
35	      startY: number;
36	      origX: number;
37	      origY: number;
38	    }
39	  | {
40	      kind: "resize";
41	      shapeId: string;
42	      corner: string;
43	      startX: number;
44	      startY: number;
45	      origX: number;
46	      origY: number;
47	      origW: number;
48	      origH: number;
49	    };
50	
51	export default function CanvasPage({
52	  canvasId,
53	  onBack,
54	  onLogout,
55	}: CanvasPageProps) {
56	  // --- State stored in refs for high-frequency access ---
57	  const shapesRef = useRef<Shape[]>([]);
58	  const undoStackRef = useRef<UndoEntry[]>([]);
59	  const redoStackRef = useRef<UndoEntry[]>([]);
60	  const pendingOpsRef = useRef<Set<string>>(new Set());
61	  const cursorsRef = useRef<Map<string, CursorInfo>>(new Map());
62	  const onlineUsersRef = useRef<PresenceUser[]>([]);
63	  const selectedIdRef = useRef<string | null>(null);
64	  const dragModeRef = useRef<DragMode>({ kind: "none" });
65	  const wsRef = useRef<WebSocket | null>(null);
66	  const seqRef = useRef<number>(0);
67	  const canvasRef = useRef<HTMLCanvasElement | null>(null);
68	  const containerRef = useRef<HTMLDivElement | null>(null);
69	  const lastCursorSendRef = useRef<number>(0);
70	  const mountedRef = useRef(false);
71	  const wsInitReceivedRef = useRef(false);
72	
73	  // --- React state for UI that needs re-renders ---
74	  const [currentTool, setCurrentTool] = useState<Tool>("select");
75	  const [fillColor, setFillColor] = useState("#3498db");
76	  const [strokeColor, setStrokeColor] = useState("#000000");
77	  const [undoCount, setUndoCount] = useState(0);
78	  const [redoCount, setRedoCount] = useState(0);
79	  const [onlineUsers, setOnlineUsers] = useState<PresenceUser[]>([]);
80	  const [wsConnected, setWsConnected] = useState(false);
81	  const [error, setError] = useState("");
82	
83	  // --- Rendering ---
84	  const scheduleRender = useCallback(() => {
85	    const canvas = canvasRef.current;
86	    if (!canvas) return;
87	    const ctx = canvas.getContext("2d");
88	    if (!ctx) return;
89	    const dpr = window.devicePixelRatio || 1;
90	    const rect = canvas.getBoundingClientRect();
91	
92	    const selection = selectedIdRef.current
93	      ? {
94	          shapeId: selectedIdRef.current,
95	          handles: [],
96	        }
97	      : null;
98	
99	    const drag = dragModeRef.current;
100	    const preview = drag.kind === "draw" ? drag.previewShape : null;
101	
102	    renderScene(
103	      ctx,
104	      shapesRef.current,
105	      selection,
106	      cursorsRef.current,
107	      preview,
108	      rect.width,
109	      rect.height,
110	      dpr
111	    );
112	  }, []);
113	
114	  const renderRef = useRef(scheduleRender);
115	  renderRef.current = scheduleRender;
116	
117	  const requestRender = useCallback(() => {
118	    requestAnimationFrame(() => renderRef.current());
119	  }, []);
120	
121	  // --- WebSocket Send Helpers ---
122	  const sendWs = useCallback((msg: ClientMessage) => {
123	    const ws = wsRef.current;
124	    if (ws && ws.readyState === WebSocket.OPEN) {
125	      ws.send(JSON.stringify(msg));
126	    }
127	  }, []);
128	
129	  const sendOp = useCallback(
130	    (op: Operation) => {
131	      const ws = wsRef.current;
132	      if (!ws || ws.readyState !== WebSocket.OPEN) return; // drop if not connected
133	      const opId = crypto.randomUUID();
134	      // Apply optimistically
135	      shapesRef.current = applyOp(shapesRef.current, op);
136	      pendingOpsRef.current.add(opId);
137	      ws.send(JSON.stringify({ type: "op", op, opId } satisfies ClientMessage));
138	      requestRender();
139	    },
140	    [requestRender]
141	  );
142	
143	  const doAction = useCallback(
144	    (forward: Operation, reverse: Operation) => {
145	      const ws = wsRef.current;
146	      if (!ws || ws.readyState !== WebSocket.OPEN) return; // don't push undo for unsent ops
147	      undoStackRef.current = [...undoStackRef.current, { forward, reverse }];
148	      redoStackRef.current = [];
149	      setUndoCount(undoStackRef.current.length);
150	      setRedoCount(0);
151	      sendOp(forward);
152	    },
153	    [sendOp]
154	  );
155	
156	  // --- Undo/Redo ---
157	  const undo = useCallback(() => {
158	    const stack = undoStackRef.current;
159	    if (stack.length === 0) return;
160	    const entry = stack[stack.length - 1];
161	    undoStackRef.current = stack.slice(0, -1);
162	    redoStackRef.current = [...redoStackRef.current, entry];
163	    setUndoCount(undoStackRef.current.length);
164	    setRedoCount(redoStackRef.current.length);
165	    sendOp(entry.reverse);
166	  }, [sendOp]);
167	
168	  const redo = useCallback(() => {
169	    const stack = redoStackRef.current;
170	    if (stack.length === 0) return;
171	    const entry = stack[stack.length - 1];
172	    redoStackRef.current = stack.slice(0, -1);
173	    undoStackRef.current = [...undoStackRef.current, entry];
174	    setUndoCount(undoStackRef.current.length);
175	    setRedoCount(redoStackRef.current.length);
176	    sendOp(entry.forward);
177	  }, [sendOp]);
178	
179	  // --- Color change for selected shape ---
180	  // Track the color before the picker opens for a single undo entry
181	  const colorBeforeRef = useRef<{ fill: string; stroke: string }>({ fill: "", stroke: "" });
182	  const colorTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
183	
184	  const handleFillChange = useCallback(
185	    (color: string) => {
186	      setFillColor(color);
187	      const selId = selectedIdRef.current;
188	      if (!selId) return;
189	      // Capture original color on first change of a drag
190	      if (!colorBeforeRef.current.fill) {
191	        const shape = shapesRef.current.find((s) => s.id === selId);
192	        if (shape) colorBeforeRef.current.fill = shape.fill;
193	      }
194	      // Apply visually immediately
195	      shapesRef.current = shapesRef.current.map((s) =>
196	        s.id === selId ? { ...s, fill: color } : s
197	      );
198	      requestRender();
199	      // Debounce: send one op after picker settles
200	      if (colorTimerRef.current) clearTimeout(colorTimerRef.current);
201	      colorTimerRef.current = setTimeout(() => {
202	        const origFill = colorBeforeRef.current.fill;
203	        colorBeforeRef.current.fill = "";
204	        if (origFill && origFill !== color) {
205	          // Revert visual, then go through doAction for proper undo entry
206	          shapesRef.current = shapesRef.current.map((s) =>
207	            s.id === selId ? { ...s, fill: origFill } : s
208	          );
209	          doAction(
210	            { kind: "update", shapeId: selId, props: { fill: color } },
211	            { kind: "update", shapeId: selId, props: { fill: origFill } }
212	          );
213	        }
214	      }, 300);
215	    },
216	    [doAction, requestRender]
217	  );
218	
219	  const handleStrokeChange = useCallback(
220	    (color: string) => {
221	      setStrokeColor(color);
222	      const selId = selectedIdRef.current;
223	      if (!selId) return;
224	      if (!colorBeforeRef.current.stroke) {
225	        const shape = shapesRef.current.find((s) => s.id === selId);
226	        if (shape) colorBeforeRef.current.stroke = shape.stroke;
227	      }
228	      shapesRef.current = shapesRef.current.map((s) =>
229	        s.id === selId ? { ...s, stroke: color } : s
230	      );
231	      requestRender();
232	      if (colorTimerRef.current) clearTimeout(colorTimerRef.current);
233	      colorTimerRef.current = setTimeout(() => {
234	        const origStroke = colorBeforeRef.current.stroke;
235	        colorBeforeRef.current.stroke = "";
236	        if (origStroke && origStroke !== color) {
237	          shapesRef.current = shapesRef.current.map((s) =>
238	            s.id === selId ? { ...s, stroke: origStroke } : s
239	          );
240	          doAction(
241	            { kind: "update", shapeId: selId, props: { stroke: color } },
242	            { kind: "update", shapeId: selId, props: { stroke: origStroke } }
243	          );
244	        }
245	      }, 300);
246	    },
247	    [doAction, requestRender]
248	  );
249	
250	  // --- Canvas coordinate helper ---
251	  const getCanvasCoords = useCallback(
252	    (e: MouseEvent): { x: number; y: number } => {
253	      const canvas = canvasRef.current;
254	      if (!canvas) return { x: 0, y: 0 };
255	      const rect = canvas.getBoundingClientRect();
256	      return {
257	        x: e.clientX - rect.left,
258	        y: e.clientY - rect.top,
259	      };
260	    },
261	    []
262	  );
263	
264	  // --- Mouse Handlers ---
265	  const handleMouseDown = useCallback(
266	    (e: MouseEvent) => {
267	      e.preventDefault(); // prevent text selection during drag
268	      const { x, y } = getCanvasCoords(e);
269	
270	      // Text tool: prompt for text and create shape
271	      if (currentTool === "text") {
272	        const text = prompt("Enter text:");
273	        if (!text) return;
274	        const fontSize = 20;
275	        const newShape: Shape = {
276	          id: crypto.randomUUID(),
277	          type: "text",
278	          x,
279	          y,
280	          width: text.length * fontSize * 0.6,
281	          height: fontSize,
282	          fill: fillColor,
283	          stroke: strokeColor,
284	          strokeWidth: 0,
285	          text,
286	          fontSize,
287	        };
288	        const forward: Operation = { kind: "add", shape: newShape };
289	        const reverse: Operation = { kind: "delete", shapeId: newShape.id };
290	        doAction(forward, reverse);
291	        selectedIdRef.current = newShape.id;
292	        requestRender();
293	        return;
294	      }
295	
296	      // Select tool: hit test
297	      if (currentTool === "select") {
298	        // Check if clicking on a resize handle of selected shape
299	        const selId = selectedIdRef.current;
300	        if (selId) {
301	          const selShape = shapesRef.current.find((s) => s.id === selId);
302	          if (selShape) {
303	            const corner = hitTestHandle(selShape, x, y);
304	            if (corner) {
305	              dragModeRef.current = {
306	                kind: "resize",
307	                shapeId: selId,
308	                corner,
309	                startX: x,
310	                startY: y,
311	                origX: selShape.x,
312	                origY: selShape.y,
313	                origW: selShape.width,
314	                origH: selShape.height,
315	              };
316	              return;
317	            }
318	          }
319	        }
320	
321	        // Hit test shapes
322	        const hit = hitTest(shapesRef.current, x, y);
323	        if (hit) {
324	          selectedIdRef.current = hit.id;
325	          dragModeRef.current = {
326	            kind: "move",
327	            shapeId: hit.id,
328	            startX: x,
329	            startY: y,
330	            origX: hit.x,
331	            origY: hit.y,
332	          };
333	          requestRender();
334	        } else {
335	          selectedIdRef.current = null;
336	          dragModeRef.current = { kind: "none" };
337	          requestRender();
338	        }
339	        return;
340	      }
341	
342	      // Drawing tools: start preview shape
343	      const shapeType = currentTool as ShapeType;
344	      const previewShape: Shape = {
345	        id: crypto.randomUUID(),
346	        type: shapeType,
347	        x,
348	        y,
349	        width: 0,
350	        height: 0,
351	        fill: shapeType === "line" ? "" : fillColor,
352	        stroke: strokeColor,
353	        strokeWidth: 2,
354	      };
355	      dragModeRef.current = {
356	        kind: "draw",
357	        startX: x,
358	        startY: y,
359	        previewShape,
360	      };
361	      requestRender();
362	    },
363	    [currentTool, fillColor, strokeColor, getCanvasCoords, doAction, requestRender]
364	  );
365	
366	  const handleMouseMove = useCallback(
367	    (e: MouseEvent) => {
368	      const { x, y } = getCanvasCoords(e);
369	
370	      // Send cursor position throttled
371	      const now = Date.now();
372	      if (now - lastCursorSendRef.current >= 30) {
373	        lastCursorSendRef.current = now;
374	        sendWs({ type: "cursor", x, y });
375	      }
376	
377	      const drag = dragModeRef.current;
378	
379	      if (drag.kind === "draw") {
380	        const dx = x - drag.startX;
381	        const dy = y - drag.startY;
382	        drag.previewShape = {
383	          ...drag.previewShape,
384	          x: dx < 0 ? drag.startX + dx : drag.startX,
385	          y: dy < 0 ? drag.startY + dy : drag.startY,
386	          width: Math.abs(dx),
387	          height: Math.abs(dy),
388	        };
389	        // For line, keep the original start and use delta as width/height
390	        if (drag.previewShape.type === "line") {
391	          drag.previewShape.x = drag.startX;
392	          drag.previewShape.y = drag.startY;
393	          drag.previewShape.width = dx;
394	          drag.previewShape.height = dy;
395	        }
396	        requestRender();
397	        return;
398	      }
399	
400	      if (drag.kind === "move") {
401	        const dx = x - drag.startX;
402	        const dy = y - drag.startY;
403	        // Update local shape position for live preview (non-optimistic, just visual)
404	        shapesRef.current = shapesRef.current.map((s) =>
405	          s.id === drag.shapeId
406	            ? { ...s, x: drag.origX + dx, y: drag.origY + dy }
407	            : s
408	        );
409	        requestRender();
410	        return;
411	      }
412	
413	      if (drag.kind === "resize") {
414	        const dx = x - drag.startX;
415	        const dy = y - drag.startY;
416	        let newX = drag.origX;
417	        let newY = drag.origY;
418	        let newW = drag.origW;
419	        let newH = drag.origH;
420	
421	        if (drag.corner.includes("e")) {
422	          newW = drag.origW + dx;
423	        }
424	        if (drag.corner.includes("w")) {
425	          newX = drag.origX + dx;
426	          newW = drag.origW - dx;
427	        }
428	        if (drag.corner.includes("s")) {
429	          newH = drag.origH + dy;
430	        }
431	        if (drag.corner.includes("n")) {
432	          newY = drag.origY + dy;
433	          newH = drag.origH - dy;
434	        }
435	
436	        shapesRef.current = shapesRef.current.map((s) =>
437	          s.id === drag.shapeId
438	            ? { ...s, x: newX, y: newY, width: newW, height: newH }
439	            : s
440	        );
441	        requestRender();
442	        return;
443	      }
444	    },
445	    [getCanvasCoords, sendWs, requestRender]
446	  );
447	
448	  const handleMouseUp = useCallback(
449	    (_e: MouseEvent) => {
450	      const drag = dragModeRef.current;
451	
452	      if (drag.kind === "draw") {
453	        const shape = drag.previewShape;
454	        // Only add if shape has some size (or is a line with any length)
455	        if (
456	          Math.abs(shape.width) > 2 ||
457	          Math.abs(shape.height) > 2
458	        ) {
459	          const forward: Operation = { kind: "add", shape };
460	          const reverse: Operation = { kind: "delete", shapeId: shape.id };
461	          doAction(forward, reverse);
462	          selectedIdRef.current = shape.id;
463	        }
464	        dragModeRef.current = { kind: "none" };
465	        requestRender();
466	        return;
467	      }
468	
469	      if (drag.kind === "move") {
470	        const shape = shapesRef.current.find((s) => s.id === drag.shapeId);
471	        if (shape && (shape.x !== drag.origX || shape.y !== drag.origY)) {
472	          // Revert local change, then do proper action through undo system
473	          shapesRef.current = shapesRef.current.map((s) =>
474	            s.id === drag.shapeId
475	              ? { ...s, x: drag.origX, y: drag.origY }
476	              : s
477	          );
478	          const forward: Operation = {
479	            kind: "update",
480	            shapeId: drag.shapeId,
481	            props: { x: shape.x, y: shape.y },
482	          };
483	          const reverse: Operation = {
484	            kind: "update",
485	            shapeId: drag.shapeId,
486	            props: { x: drag.origX, y: drag.origY },
487	          };
488	          doAction(forward, reverse);
489	        }
490	        dragModeRef.current = { kind: "none" };
491	        requestRender();
492	        return;
493	      }
494	
495	      if (drag.kind === "resize") {
496	        const shape = shapesRef.current.find((s) => s.id === drag.shapeId);
497	        if (shape) {
498	          const newProps: ShapePatch = {
499	            x: shape.x,
500	            y: shape.y,
501	            width: shape.width,
502	            height: shape.height,
503	          };
504	          const oldProps: ShapePatch = {
505	            x: drag.origX,
506	            y: drag.origY,
507	            width: drag.origW,
508	            height: drag.origH,
509	          };
510	          // Revert local change, then go through undo system
511	          shapesRef.current = shapesRef.current.map((s) =>
512	            s.id === drag.shapeId
513	              ? { ...s, ...oldProps }
514	              : s
515	          );
516	          const forward: Operation = {
517	            kind: "update",
518	            shapeId: drag.shapeId,
519	            props: newProps,
520	          };
521	          const reverse: Operation = {
522	            kind: "update",
523	            shapeId: drag.shapeId,
524	            props: oldProps,
525	          };
526	          doAction(forward, reverse);
527	        }
528	        dragModeRef.current = { kind: "none" };
529	        requestRender();
530	        return;
531	      }
532	    },
533	    [doAction, requestRender]
534	  );
535	
536	  // --- Keyboard Handlers ---
537	  const handleKeyDown = useCallback(
538	    (e: KeyboardEvent) => {
539	      // Undo: Ctrl+Z (not Shift)
540	      if (e.ctrlKey && !e.shiftKey && e.key === "z") {
541	        e.preventDefault();
542	        undo();
543	        return;
544	      }
545	      // Redo: Ctrl+Shift+Z or Ctrl+Y
546	      if (
547	        (e.ctrlKey && e.shiftKey && e.key === "Z") ||
548	        (e.ctrlKey && e.key === "y")
549	      ) {
550	        e.preventDefault();
551	        redo();
552	        return;
553	      }
554	      // Delete selected shape
555	      if (
556	        (e.key === "Delete" || e.key === "Backspace") &&
557	        selectedIdRef.current
558	      ) {
559	        e.preventDefault();
560	        const shapeId = selectedIdRef.current;
561	        const shape = shapesRef.current.find((s) => s.id === shapeId);
562	        if (shape) {
563	          const forward: Operation = { kind: "delete", shapeId };
564	          const reverse: Operation = { kind: "add", shape: { ...shape } };
565	          selectedIdRef.current = null;
566	          doAction(forward, reverse);
567	          requestRender();
568	        }
569	        return;
570	      }
571	    },
572	    [undo, redo, doAction, requestRender]
573	  );
574	
575	  // --- Canvas Resize ---
576	  const resizeCanvas = useCallback(() => {
577	    const canvas = canvasRef.current;
578	    const container = containerRef.current;
579	    if (!canvas || !container) return;
580	    const dpr = window.devicePixelRatio || 1;
581	    const rect = container.getBoundingClientRect();
582	    canvas.style.width = `${rect.width}px`;
583	    canvas.style.height = `${rect.height}px`;
584	    canvas.width = rect.width * dpr;
585	    canvas.height = rect.height * dpr;
586	    requestRender();
587	  }, [requestRender]);
588	
589	  // --- WebSocket Connection ---
590	  useEffect(() => {
591	    // StrictMode double-mount guard
592	    if (mountedRef.current) return;
593	    mountedRef.current = true;
594	
595	    const token = getStoredToken();
596	    if (!token) {
597	      onLogout();
598	      return;
599	    }
600	
601	    // Load initial canvas data via HTTP as fallback — WS init takes precedence
602	    getCanvasDetail(canvasId)
603	      .then((detail) => {
604	        if (!wsInitReceivedRef.current) {
605	          shapesRef.current = detail.shapes;
606	          requestRender();
607	        }
608	      })
609	      .catch((err) => {
610	        if (err instanceof ApiError && (err.status === 401 || err.status === 403)) {
611	          setError("Access denied.");
612	        } else {
613	          setError("Failed to load canvas.");
614	        }
615	      });
616	
617	    // Connect WebSocket
618	    const protocol = window.location.protocol === "https:" ? "wss:" : "ws:";
619	    const host = window.location.host;
620	    const wsUrl = `${protocol}//${host}/ws?canvasId=${canvasId}&token=${token}`;
621	    const ws = new WebSocket(wsUrl);
622	    wsRef.current = ws;
623	
624	    ws.onopen = () => {
625	      setWsConnected(true);
626	    };
627	
628	    ws.onmessage = (event) => {
629	      let msg: ServerMessage;
630	      try {
631	        msg = JSON.parse(event.data) as ServerMessage;
632	      } catch {
633	        return;
634	      }
635	
636	      switch (msg.type) {
637	        case "init":
638	          wsInitReceivedRef.current = true;
639	          shapesRef.current = msg.shapes;
640	          seqRef.current = msg.seq;
641	          onlineUsersRef.current = msg.users;
642	          // Clear stale state from previous session (C3+C4)
643	          undoStackRef.current = [];
644	          redoStackRef.current = [];
645	          pendingOpsRef.current.clear();
646	          setUndoCount(0);
647	          setRedoCount(0);
648	          setOnlineUsers([...msg.users]);
649	          requestRender();
650	          break;
651	
652	        case "op": {
653	          const isOwnEcho = pendingOpsRef.current.has(msg.opId);
654	          if (isOwnEcho) {
655	            pendingOpsRef.current.delete(msg.opId);
656	          }
657	          // For "add" ops that we sent: skip (shape already in array).
658	          // For "update"/"delete" ops: ALWAYS re-apply from server to
659	          // guarantee server-authoritative ordering under concurrent edits.
660	          if (isOwnEcho && msg.op.kind === "add") {
661	            // Already added optimistically — skip to avoid duplicate
662	          } else {
