146	function drawCursor(ctx: CanvasRenderingContext2D, cursor: CursorInfo): void {
147	  ctx.save();
148	
149	  // Draw cursor arrow
150	  ctx.fillStyle = cursor.color;
151	  ctx.strokeStyle = "#ffffff";
152	  ctx.lineWidth = 1;
153	
154	  ctx.beginPath();
155	  ctx.moveTo(cursor.x, cursor.y);
156	  ctx.lineTo(cursor.x, cursor.y + 16);
157	  ctx.lineTo(cursor.x + 5, cursor.y + 12);
158	  ctx.lineTo(cursor.x + 10, cursor.y + 12);
159	  ctx.closePath();
160	  ctx.fill();
161	  ctx.stroke();
162	
163	  // Draw username label
164	  ctx.font = "11px sans-serif";
165	  const metrics = ctx.measureText(cursor.username);
166	  const labelX = cursor.x + 12;
167	  const labelY = cursor.y + 10;
168	  const padding = 3;
169	
170	  ctx.fillStyle = cursor.color;
171	  const rx = labelX - padding;
172	  const ry2 = labelY - 10 - padding;
173	  const rw = metrics.width + padding * 2;
174	  const rh = 14 + padding * 2;
175	  const r = 3;
176	  ctx.beginPath();
177	  ctx.moveTo(rx + r, ry2);
178	  ctx.lineTo(rx + rw - r, ry2);
179	  ctx.arcTo(rx + rw, ry2, rx + rw, ry2 + r, r);
180	  ctx.lineTo(rx + rw, ry2 + rh - r);
181	  ctx.arcTo(rx + rw, ry2 + rh, rx + rw - r, ry2 + rh, r);
182	  ctx.lineTo(rx + r, ry2 + rh);
183	  ctx.arcTo(rx, ry2 + rh, rx, ry2 + rh - r, r);
184	  ctx.lineTo(rx, ry2 + r);
185	  ctx.arcTo(rx, ry2, rx + r, ry2, r);
186	  ctx.closePath();
187	  ctx.fill();
188	
189	  ctx.fillStyle = "#ffffff";
190	  ctx.fillText(cursor.username, labelX, labelY);
191	
192	  ctx.restore();
193	}
